#include<bits/stdc++.h>
using namespace std;

const int N = 105;

int dfn[N], vis[N], low[N], s[N], dfncnt, sz[N], scc[N], tp, sc;
int in_deg[N], out_deg[N];
vector<int> e[N];

void tarjan(int u) {
    low[u] = dfn[u] = ++dfncnt;
    s[++tp] = u;
    vis[u] = 1;
    for (int v : e[u]) {
        if (!dfn[v]) {
            tarjan(v);
            low[u] = min(low[u], low[v]);
        } 
        else if (vis[v]) {
            low[u] = min(low[u], dfn[v]);
        }
    }
    if (dfn[u] == low[u]) {
        ++sc;
        do {
            scc[s[tp]] = sc;
            sz[sc]++;
            vis[s[tp]] = 0;
        } while (s[tp--] != u);
    }
}

int main() {
    int n;
    cin >> n;

    for(int i = 1; i <= n; i++) {
        int v;
        while(cin >> v && v != 0) {
            e[i].push_back(v);
        }
    }

    dfncnt = tp = sc = 0;
    memset(dfn, 0, sizeof(dfn));
    memset(vis, 0, sizeof(vis));
    memset(sz, 0, sizeof(sz));

    for(int i = 1; i <= n; i++) {
        if(!dfn[i]) {
            tarjan(i);
        }
    }

    if(sc == 1) {
        cout << 1 << endl << 0 << endl;
        return 0;
    }

    memset(in_deg, 0, sizeof(in_deg));
    memset(out_deg, 0, sizeof(out_deg));

    for(int u = 1; u <= n; u++) {
        for(int v : e[u]) {
            if(scc[u] != scc[v]) {
                out_deg[scc[u]]++;
                in_deg[scc[v]]++;
            }
        }
    }

    int in_zero = 0, out_zero = 0;
    for(int i = 1; i <= sc; i++) {
        if(in_deg[i] == 0) in_zero++;
        if(out_deg[i] == 0) out_zero++;
    }

    cout << in_zero << endl;
    cout << max(in_zero, out_zero) << endl;

    return 0;
}
